package com.example.dms.seed;
import com.example.dms.customer.*;import com.example.dms.inventory.*;import com.example.dms.product.*;import com.example.dms.tenant.*;import com.example.dms.user.*;import lombok.*;import org.springframework.boot.CommandLineRunner;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Component;import org.springframework.transaction.annotation.Transactional;import java.math.*;import java.util.*;
@Component @RequiredArgsConstructor
public class SeedDataRunner implements CommandLineRunner {
 private final TenantRepository tenants; private final PermissionRepository perms; private final RoleRepository roles; private final AppUserRepository users; private final PasswordEncoder encoder; private final ProductRepository products; private final CustomerRepository customers; private final InventoryService inventory; private final EntityManagerHelper emh;
 @Override @Transactional public void run(String...args){ if(users.count()>0)return; Tenant t=tenants.save(Tenant.builder().name("Demo Distributor").active(true).build()); List<String> ps=List.of("PRODUCT_VIEW","PRODUCT_MANAGE","CUSTOMER_VIEW","CUSTOMER_MANAGE","SALES_ORDER_CREATE","SALES_ORDER_CONFIRM","INVENTORY_VIEW","PAYMENT_CREATE","DEBT_VIEW","REPORT_VIEW"); Set<Permission> all=new HashSet<>(); for(String p:ps) all.add(perms.save(Permission.builder().name(p).build())); Role owner=roles.save(Role.builder().name("OWNER").permissions(all).build()); Role sale=roles.save(Role.builder().name("SALE_STAFF").permissions(new HashSet<>(all)).build()); users.save(AppUser.builder().username("owner").passwordHash(encoder.encode("123456")).fullName("Owner").tenantId(t.getId()).active(true).roles(Set.of(owner)).build()); users.save(AppUser.builder().username("sale").passwordHash(encoder.encode("123456")).fullName("Sale").tenantId(t.getId()).active(true).roles(Set.of(sale)).build()); users.save(AppUser.builder().username("warehouse").passwordHash(encoder.encode("123456")).fullName("Warehouse").tenantId(t.getId()).active(true).roles(Set.of(owner)).build()); users.save(AppUser.builder().username("accountant").passwordHash(encoder.encode("123456")).fullName("Accountant").tenantId(t.getId()).active(true).roles(Set.of(owner)).build()); emh.insertWarehouse(t.getId()); Product p1=products.save(Product.builder().tenantId(t.getId()).name("Nước suối thùng 24 chai").sku("WATER-24").costPrice(new BigDecimal("65000")).sellingPrice(new BigDecimal("80000")).minStock(10).active(true).build()); Product p2=products.save(Product.builder().tenantId(t.getId()).name("Trà xanh thùng 24 chai").sku("TEA-24").costPrice(new BigDecimal("120000")).sellingPrice(new BigDecimal("150000")).minStock(8).active(true).build()); inventory.increase(t.getId(),1L,p1.getId(),50,"ADJUSTMENT",null,"Seed stock"); inventory.increase(t.getId(),1L,p2.getId(),30,"ADJUSTMENT",null,"Seed stock"); customers.save(Customer.builder().tenantId(t.getId()).name("Tạp hóa Cô Lan").phone("0909000001").address("Quận 1").creditLimit(new BigDecimal("20000000")).paymentTermDays(14).active(true).build()); }
}
@Component @RequiredArgsConstructor class EntityManagerHelper{ private final jakarta.persistence.EntityManager em; void insertWarehouse(Long tenantId){em.createNativeQuery("insert into warehouses(tenant_id,name) values(:t,'Kho chính')").setParameter("t",tenantId).executeUpdate();}}
